from typing import List, Dict, Optional

from src.utils.vectordb import LanceDB
from src.utils.llm import get_embedding
from src.base import DefaultConfig


class ExperienceCollector:
    def __init__(self, db_url: str = ".rag/experience"):
        self.db = LanceDB(db_url)
        self.embedding_model = get_embedding(
            openai_api_base=DefaultConfig.embedding_api_base,
            openai_api_key=DefaultConfig.embedding_api_key,
            model_name=DefaultConfig.embedding_model,
        )

    def add_experience(
        self,
        text: str,
        metadata: Optional[Dict] = None,
        embedding: Optional[List[float]] = None,
        table_name: str = "experience",
    ) -> None:
        if embedding is None:
            embedding = self.embedding_model.embed_query(text)

        record = {
            "text": text,
            "vector": embedding,
            "metadata": metadata or {},
        }

        self.db.append_data(table_name, [record])

    def search_experience(
        self,
        query: str,
        limit: int = 3,
        embedding: Optional[List[float]] = None,
        table_name: str = "experience",
    ) -> List[Dict]:
        if embedding is None:
            embedding = self.embedding_model.embed_query(query)

        result = self.db.vector_search(table_name, embedding, limit)
        if result is None:
            return None
        return [item["text"] for item in result]


